import React, { useState } from 'react';
import { useApp } from '../../context/AppContext';
import { Mail, User } from 'lucide-react';
import './Auth.css';

const demoCredentials = {
  admin: { email: 'admin@dulceria.com', password: '123456' },
  cliente: { email: 'maria@dulceria.com', password: '123456' },
  vendor: { email: 'laura@dulceria.com', password: '123456' },
};

export default function AuthPage() {
  const { login, register } = useApp();
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [showPass, setShowPass] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const handle = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const resetMessages = () => {
    setError('');
    setSuccessMsg('');
  };

  const submit = (e) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    if (mode === 'login') {
      const res = login(form.email, form.password);
      if (res.error) setError(res.error);
      return;
    }

    if (mode === 'register') {
      if (!form.name.trim()) {
        setError('El nombre es requerido.');
        return;
      }

      const res = register(form.name, form.email, form.password);
      if (res.error) setError(res.error);
      return;
    }

    setSuccessMsg('Si el correo existe, recibirás instrucciones para restablecer tu contraseña.');
  };

  const demo = (accountRole) => {
    const credentials = demoCredentials[accountRole];
    login(credentials.email, credentials.password);
  };

  if (mode === 'forgot') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background px-4 py-8">
        <div className="max-w-md w-full p-8 bg-white rounded-xl shadow-lg">
          <h2 className="text-2xl font-semibold mb-4">Recuperar contraseña</h2>
          <p className="text-sm text-secondary mb-4">Ingresa tu correo y te enviaremos instrucciones para restablecer tu contraseña.</p>
          {error && <div className="mb-3 text-sm text-red-600">{error}</div>}
          {successMsg && <div className="mb-3 text-sm text-green-600">{successMsg}</div>}

          <form onSubmit={submit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-secondary mb-1" htmlFor="forgot-email">Correo electrónico</label>
              <input
                id="forgot-email"
                name="email"
                type="email"
                placeholder="correo@ejemplo.com"
                value={form.email}
                onChange={handle}
                required
                className="w-full px-4 py-3 border rounded-lg"
              />
            </div>

            <button type="submit" className="w-full py-3 bg-primary text-white rounded-lg">Enviar instrucciones</button>

            <div className="text-center mt-2">
              <button type="button" className="text-sm text-primary" onClick={() => { setMode('login'); resetMessages(); }}>
                Volver a inicio
              </button>
            </div>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-background px-4 py-8">
      <main className="w-full max-w-[1100px] grid md:grid-cols-2 bg-surface-container-lowest rounded-xl overflow-hidden soft-glow relative z-10">
        <div className="hidden md:block relative h-full min-h-[600px]">
          <img
            className="w-full h-full object-cover"
            src={process.env.PUBLIC_URL + '/img/dulces/canasto.png'}
            alt="Canasto de dulces"
          />
          <div className="absolute inset-0 bg-primary/10 mix-blend-overlay"></div>
          <div className="absolute bottom-12 left-12 right-12 text-on-primary">
            <h2 className="font-headline-lg text-headline-lg text-white mb-stack-sm leading-tight">
              Artisan Sweets, Crafted with Love.
            </h2>
            <p className="font-body-md text-body-md text-white/90">
              Experience the magic of traditional confectionery reinvented for modern palates.
            </p>
          </div>
        </div>

        <div className="p-8 md:p-16 flex flex-col justify-center">
          <div className="mb-12 text-center md:text-left">
            <h1 className="font-headline-lg text-headline-lg text-primary tracking-tight mb-2">Dulcería El Suspiro</h1>
            <p className="font-body-md text-body-md text-secondary">
              {mode === 'login'
                ? 'Welcome back! Please enter your details.'
                : mode === 'register'
                  ? 'Create your account to continue.'
                  : 'Reset your password.'}
            </p>
          </div>

          {error && <div className="mb-3 text-sm text-red-600">{error}</div>}
          {successMsg && <div className="mb-3 text-sm text-green-600">{successMsg}</div>}

          <div className="flex gap-3 mb-6">
            <button
              type="button"
              className={mode === 'login' ? 'px-4 py-2 rounded-lg bg-primary text-white' : 'px-4 py-2 rounded-lg border'}
              onClick={() => { setMode('login'); resetMessages(); }}
            >
              Ingreso
            </button>
            <button
              type="button"
              className={mode === 'register' ? 'px-4 py-2 rounded-lg bg-primary text-white' : 'px-4 py-2 rounded-lg border'}
              onClick={() => { setMode('register'); resetMessages(); }}
            >
              Registro
            </button>
          </div>

          <form onSubmit={submit} className="space-y-stack-md">
            {mode === 'register' && (
              <div className="space-y-2">
                <label className="font-label-md text-label-md text-on-secondary-fixed-variant" htmlFor="name">Nombre completo</label>
                <div className="relative group">
                  <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary transition-colors">person</span>
                  <input
                    className="w-full pl-12 pr-4 py-4 bg-secondary-container/30 border-b-2 border-secondary focus:border-primary focus:ring-0 transition-all outline-none font-body-md text-on-surface placeholder:text-outline/50"
                    id="name"
                    name="name"
                    type="text"
                    placeholder="Tu nombre"
                    value={form.name}
                    onChange={handle}
                    required
                  />
                </div>
              </div>
            )}

            <div className="space-y-2">
              <label className="font-label-md text-label-md text-on-secondary-fixed-variant" htmlFor="email">Email Address</label>
              <div className="relative group">
                <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary transition-colors">mail</span>
                <input
                  className="w-full pl-12 pr-4 py-4 bg-secondary-container/30 border-b-2 border-secondary focus:border-primary focus:ring-0 transition-all outline-none font-body-md text-on-surface placeholder:text-outline/50"
                  id="email"
                  name="email"
                  placeholder="hello@example.com"
                  type="email"
                  value={form.email}
                  onChange={handle}
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between items-center">
                <label className="font-label-md text-label-md text-on-secondary-fixed-variant" htmlFor="password">Password</label>
                {mode === 'login' && (
                  <button
                    type="button"
                    className="font-label-md text-label-md text-primary hover:underline transition-all"
                    onClick={() => { setMode('forgot'); resetMessages(); }}
                  >
                    Forgot?
                  </button>
                )}
              </div>
              <div className="relative group">
                <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-outline group-focus-within:text-primary transition-colors">lock</span>
                <input
                  className="w-full pl-12 pr-12 py-4 bg-secondary-container/30 border-b-2 border-secondary focus:border-primary focus:ring-0 transition-all outline-none font-body-md text-on-surface placeholder:text-outline/50"
                  id="password"
                  name="password"
                  placeholder="••••••••"
                  type={showPass ? 'text' : 'password'}
                  value={form.password}
                  onChange={handle}
                  required
                />
                <button
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-outline hover:text-primary transition-colors"
                  type="button"
                  onClick={() => setShowPass(!showPass)}
                >
                  <span className="material-symbols-outlined">{showPass ? 'visibility_off' : 'visibility'}</span>
                </button>
              </div>
            </div>

            <div className="flex items-center gap-2 py-2">
              <input className="w-5 h-5 rounded border-secondary text-primary focus:ring-primary/20" id="remember" type="checkbox" />
              <label className="font-label-md text-label-md text-secondary" htmlFor="remember">Keep me signed in for 30 days</label>
            </div>

            <button className="w-full py-4 bg-primary text-on-primary font-label-md text-label-md rounded-lg soft-glow hover:bg-on-primary-fixed-variant transition-all active:scale-[0.98] duration-150" type="submit">
              {mode === 'login' ? 'Sign In' : mode === 'register' ? 'Create account' : 'Enviar instrucciones'}
            </button>
          </form>

          {mode === 'login' && (
            <>
              <div className="mt-12">
                <div className="relative flex items-center mb-10">
                  <div className="flex-grow border-t border-outline-variant"></div>
                  <span className="flex-shrink mx-4 font-label-md text-label-md text-outline">or continue with</span>
                  <div className="flex-grow border-t border-outline-variant"></div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <button className="flex items-center justify-center gap-2 py-3 border border-outline-variant rounded-lg font-label-md text-label-md text-on-surface-variant hover:bg-surface-container transition-all active:scale-[0.98]" type="button" onClick={() => demo('admin')}>
                    Google
                  </button>
                  <button className="flex items-center justify-center gap-2 py-3 border border-outline-variant rounded-lg font-label-md text-label-md text-on-surface-variant hover:bg-surface-container transition-all active:scale-[0.98]" type="button" onClick={() => demo('cliente')}>
                    Apple
                  </button>
                </div>
              </div>

              <p className="mt-12 text-center font-body-md text-body-md text-secondary">
                New to El Suspiro?{' '}
                <button className="text-primary font-bold hover:underline" type="button" onClick={() => { setMode('register'); resetMessages(); }}>
                  Create an account
                </button>
              </p>
            </>
          )}

          {mode === 'register' && (
            <p className="mt-12 text-center font-body-md text-body-md text-secondary">
              ¿Ya tienes cuenta?{' '}
              <button className="text-primary font-bold hover:underline" type="button" onClick={() => { setMode('login'); resetMessages(); }}>
                Inicia sesión
              </button>
            </p>
          )}
        </div>
      </main>
    </div>
  );
}
